exercise.solution:
.nav {
  display: flex;
  justify-content: space-between;
  align-items: center;
  height: 64px;
  padding: 0 32px;
  background: #1e1b4b;
}

.nav-logo {
  color: #fff;
  font-weight: 700;
  font-size: 1.25rem;
}

.nav-links {
  display: flex;
  gap: 24px;
}

.nav-links a {
  color: #c7d2fe;
  text-decoration: none;
}
